return await space.current.patchWidget("snake-game", {
  edits: [
    {
      action: "replace",
      path: "src/index.js",
      value: `import React, { useEffect, useMemo, useRef, useState } from "react";

const GRID_SIZE = 20;
const CELL_SIZE = 20;
const TICK_MS = 120;
const TRANSITION_MS = 110;

function randCell(exclude = []) {
  while (true) {
    const cell = {
      x: Math.floor(Math.random() * GRID_SIZE),
      y: Math.floor(Math.random() * GRID_SIZE),
    };
    if (!exclude.some((p) => p.x === cell.x && p.y === cell.y)) return cell;
  }
}

function sameCell(a, b) {
  return a.x === b.x && a.y === b.y;
}

export default function SnakeGame() {
  const [snake, setSnake] = useState([
    { x: 10, y: 10 },
    { x: 9, y: 10 },
    { x: 8, y: 10 },
  ]);
  const [dir, setDir] = useState({ x: 1, y: 0 });
  const [nextDir, setNextDir] = useState({ x: 1, y: 0 });
  const [food, setFood] = useState(() => randCell(snake));
  const [running, setRunning] = useState(true);
  const [score, setScore] = useState(0);
  const [animProgress, setAnimProgress] = useState(1);

  const rafRef = useRef(null);
  const lastTickRef = useRef(performance.now());
  const accumRef = useRef(0);
  const pendingMoveRef = useRef(null);

  useEffect(() => {
    const onKeyDown = (e) => {
      const keyMap = {
        ArrowUp: { x: 0, y: -1 },
        ArrowDown: { x: 0, y: 1 },
        ArrowLeft: { x: -1, y: 0 },
        ArrowRight: { x: 1, y: 0 },
      };
      const nd = keyMap[e.key];
      if (!nd) return;
      setNextDir((prev) => {
        if (prev.x === -nd.x && prev.y === -nd.y) return prev;
        return nd;
      });
    };
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, []);

  useEffect(() => {
    if (!running) return;

    const step = (now) => {
      const dt = now - lastTickRef.current;
      lastTickRef.current = now;
      accumRef.current += dt;

      while (accumRef.current >= TICK_MS) {
        accumRef.current -= TICK_MS;
        setDir((d) => {
          const nd = nextDir;
          if (nd.x === -d.x && nd.y === -d.y) return d;
          return nd;
        });

        pendingMoveRef.current = true;
      }

      const p = Math.min(1, accumRef.current / TRANSITION_MS);
      setAnimProgress(p);

      if (pendingMoveRef.current) {
        setSnake((prevSnake) => {
          const d = nextDir.x === -dir.x && nextDir.y === -dir.y ? dir : nextDir;
          const head = prevSnake[0];
          const newHead = {
            x: (head.x + d.x + GRID_SIZE) % GRID_SIZE,
            y: (head.y + d.y + GRID_SIZE) % GRID_SIZE,
          };
          const ate = sameCell(newHead, food);
          const body = [newHead, ...prevSnake.slice(0, ate ? prevSnake.length : prevSnake.length - 1)];

          if (body.some((seg, idx) => idx > 0 && sameCell(seg, newHead))) {
            setRunning(false);
            return prevSnake;
          }

          if (ate) {
            setFood(randCell(body));
            setScore((s) => s + 1);
          }

          return body;
        });
        pendingMoveRef.current = false;
      }

      rafRef.current = requestAnimationFrame(step);
    };

    rafRef.current = requestAnimationFrame(step);
    return () => cancelAnimationFrame(rafRef.current);
  }, [dir, nextDir, food, running]);

  const segments = useMemo(() => {
    const prevSnake = snake;
    const head = prevSnake[0];
    const d = nextDir;
    const moveDir = d.x === -dir.x && d.y === -dir.y ? dir : d;
    const prevHead = {
      x: (head.x - moveDir.x + GRID_SIZE) % GRID_SIZE,
      y: (head.y - moveDir.y + GRID_SIZE) % GRID_SIZE,
    };

    return prevSnake.map((seg, i) => {
      const from = i === 0 ? prevHead : prevSnake[i - 1];
      const to = seg;
      return { ...seg, from, to, isHead: i === 0 };
    });
  }, [snake, dir, nextDir]);

  return (
    <div style={{ fontFamily: "sans-serif", userSelect: "none" }}>
      <div style={{ marginBottom: 8 }}>Score: {score}</div>
      <div
        style={{
          width: GRID_SIZE * CELL_SIZE,
          height: GRID_SIZE * CELL_SIZE,
          position: "relative",
          background: "#111",
          border: "2px solid #333",
          overflow: "hidden",
        }}
      >
        {segments.map((seg, idx) => {
          const x = seg.from.x + (seg.to.x - seg.from.x) * animProgress;
          const y = seg.from.y + (seg.to.y - seg.from.y) * animProgress;

          return (
            <div
              key={idx}
              style={{
                position: "absolute",
                left: x * CELL_SIZE + 1,
                top: y * CELL_SIZE + 1,
                width: CELL_SIZE - 2,
                height: CELL_SIZE - 2,
                borderRadius: seg.isHead ? 8 : 6,
                background: seg.isHead ? "#8be28b" : "#5cc85c",
                boxShadow: "0 0 8px rgba(92,200,92,0.35)",
                transition: `transform ${TRANSITION_MS}ms linear`,
              }}
            />
          );
        })}

        <div
          style={{
            position: "absolute",
            left: food.x * CELL_SIZE + 3,
            top: food.y * CELL_SIZE + 3,
            width: CELL_SIZE - 6,
            height: CELL_SIZE - 6,
            borderRadius: 999,
            background: "#ff4d4d",
            boxShadow: "0 0 10px rgba(255,77,77,0.7)",
          }}
        />
      </div>
      {!running && <div style={{ marginTop: 8 }}>Game over</div>}
    </div>
  );
}
`
    }
  ]
})

