const src = await space.current.readWidget("snake-game")
const text = typeof src === "string" ? src : (src?.source ?? src?.content ?? JSON.stringify(src))

const greenThemes = [
  [/background\s*:\s*['"`]?#?[0-9a-fA-F]{3,6}['"`]?/g, "background: '#0f380f'"],
  [/bg\s*:\s*['"`]?#?[0-9a-fA-F]{3,6}['"`]?/g, "bg: '#0f380f'"],
  [/fillStyle\s*=\s*['"`]?#?[0-9a-fA-F]{3,6}['"`]?/g, "fillStyle = '#0f380f'"],
  [/backgroundColor\s*:\s*['"`]?#?[0-9a-fA-F]{3,6}['"`]?/g, "backgroundColor: '#0f380f'"],
]

let patched = text
for (const [re, repl] of greenThemes) patched = patched.replace(re, repl)

if (patched === text) {
  const insert = "\n// Nokia-style green background\nconst NOKIA_BG = '#0f380f'\nconst NOKIA_DARK = '#306230'\n"
  patched = insert + text
}

return await space.current.patchWidget("snake-game", {
  edits: [{ type: "replace", from: text, to: patched }]
})

